#include <stdio.h>
#include <stdlib.h>

// C-SCAN Disk Scheduling Algorithm
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int cscan_scheduling(int requests[], int n, int head, int disk_size) {
    int total_seek = 0;
    int current_head = head;

    // Sort requests
    int sorted[100];
    for(int i = 0; i < n; i++) sorted[i] = requests[i];
    qsort(sorted, n, sizeof(int), compare);

    printf("C-SCAN Service Order:\n");

    // Find requests greater than head
    int count = 0;
    for(int i = 0; i < n; i++) {
        if(sorted[i] >= head) {
            count = i;
            break;
        }
    }

    // Service requests > head (circular)
    for(int i = count; i < n; i++) {
        int seek = abs(current_head - sorted[i]);
        total_seek += seek;
        printf("Move %d -> %d, seek: %d\n", current_head, sorted[i], seek);
        current_head = sorted[i];
    }

    // Jump to beginning (if not already at 0)
    if(current_head != 0) {
        int seek = abs(current_head - 0);
        total_seek += seek;
        printf("Jump to start: %d -> 0, seek: %d\n", current_head, seek);
        current_head = 0;
    }

    // Service remaining requests from beginning
    for(int i = 0; i < count; i++) {
        int seek = abs(current_head - sorted[i]);
        total_seek += seek;
        printf("Move %d -> %d, seek: %d\n", current_head, sorted[i], seek);
        current_head = sorted[i];
    }

    printf("Total seek time: %d\n", total_seek);
    return total_seek;
}

int main() {
    int requests[] = {95, 180, 34, 119, 12, 190};
    int n = sizeof(requests) / sizeof(requests[0]);
    int head = 50;
    int disk_size = 200;

    cscan_scheduling(requests, n, head, disk_size);
    return 0;
}
